// 读取当前文档内容并分析结构
var doc = Application.ActiveDocument;
var content = "";
var paragraphs = doc.Paragraphs;
var paraCount = paragraphs.Count;

// 收集段落信息
var paraInfo = [];
for (var i = 1; i <= paraCount; i++) {
    var para = paragraphs.Item(i);
    var text = para.Range.Text;
    var style = para.Style.NameLocal;
    var fontSize = para.Range.Font.Size;
    var isBold = para.Range.Font.Bold;
    var alignment = para.Alignment;

    paraInfo.push({
        index: i,
        text: text.replace(/\r/g, ""),
        style: style,
        fontSize: fontSize,
        isBold: isBold,
        alignment: alignment
    });

    content += text;
}

return {
    totalParagraphs: paraCount,
    contentLength: content.length,
    paragraphs: paraInfo
};

// 根据集团公文排版格式要求对文档进行排版
var doc = Application.ActiveDocument;
var paragraphs = doc.Paragraphs;

// 1. 设置页面边距（公文标准：上3.7cm，下3.5cm，左2.8cm，右2.6cm）
doc.PageSetup.TopMargin = Application.CentimetersToPoints(3.7);
doc.PageSetup.BottomMargin = Application.CentimetersToPoints(3.5);
doc.PageSetup.LeftMargin = Application.CentimetersToPoints(2.8);
doc.PageSetup.RightMargin = Application.CentimetersToPoints(2.6);

// 2. 设置正文格式
var bodyStyle = doc.Styles.Item("正文");
bodyStyle.Font.Name = "仿宋_GB2312";
bodyStyle.Font.Size = 16; // 三号字
bodyStyle.ParagraphFormat.LineSpacingRule = 2; // 固定值
bodyStyle.ParagraphFormat.LineSpacing = 28; // 28磅行距
bodyStyle.ParagraphFormat.FirstLineIndent = Application.CentimetersToPoints(0.85); // 首行缩进2字符

// 3. 设置标题格式
var titleStyle = doc.Styles.Item("标题");
titleStyle.Font.Name = "方正小标宋简体";
titleStyle.Font.Size = 22; // 二号字
titleStyle.ParagraphFormat.Alignment = 1; // 居中
titleStyle.ParagraphFormat.SpaceBefore = 0;
titleStyle.ParagraphFormat.SpaceAfter = 0;

