heading2Style.ParagraphFormat.Alignment = 0; // 左对齐
heading2Style.ParagraphFormat.FirstLineIndent = Application.CentimetersToPoints(0.85); // 首行缩进2字符
heading2Style.ParagraphFormat.SpaceBefore = 0;
heading2Style.ParagraphFormat.SpaceAfter = 0;

// 6. 设置附件格式
var attachmentStyle = doc.Styles.Item("附件");
attachmentStyle.Font.Name = "仿宋_GB2312";
attachmentStyle.Font.Size = 16; // 三号字
attachmentStyle.ParagraphFormat.Alignment = 0; // 左对齐
attachmentStyle.ParagraphFormat.FirstLineIndent = 0; // 无缩进

