signatureStyle.Font.Name = "仿宋_GB2312";
signatureStyle.Font.Size = 16; // 三号字
signatureStyle.ParagraphFormat.Alignment = 0; // 左对齐
signatureStyle.ParagraphFormat.FirstLineIndent = 0; // 无缩进

