dateStyle.ParagraphFormat.Alignment = 0; // 左对齐
dateStyle.ParagraphFormat.FirstLineIndent = 0; // 无缩进

// 9. 应用样式到各个段落
// 第1段：标题
paragraphs.Item(1).Style = titleStyle;

// 第2段：正文（主送机关）
paragraphs.Item(2).Style = bodyStyle;

// 第3段：正文（开头）
paragraphs.Item(3).Style = bodyStyle;

// 第4段：一级标题
