// 根据集团公文排版格式要求对文档进行排版（简化版）
var doc = Application.ActiveDocument;
var paragraphs = doc.Paragraphs;

// 1. 设置页面边距（公文标准：上3.7cm，下3.5cm，左2.8cm，右2.6cm）
doc.PageSetup.TopMargin = Application.CentimetersToPoints(3.7);
doc.PageSetup.BottomMargin = Application.CentimetersToPoints(3.5);
doc.PageSetup.LeftMargin = Application.CentimetersToPoints(2.8);
doc.PageSetup.RightMargin = Application.CentimetersToPoints(2.6);

// 2. 设置正文格式（仿宋_GB2312，三号，28磅行距，首行缩进2字符）
for (var i = 1; i <= paragraphs.Count; i++) {
    var para = paragraphs.Item(i);
    var text = para.Range.Text.trim();

    // 判断段落类型并设置格式
    if (i === 1) {
        // 标题：方正小标宋简体，二号，居中
        para.Range.Font.Name = "方正小标宋简体";
        para.Range.Font.Size = 22;
        para.Range.Font.Bold = 0;
        para.Alignment = 1; // 居中
        para.Format.SpaceBefore = 0;
        para.Format.SpaceAfter = 0;
    } else if (i === 4 || i === 6 || i === 11 || i === 13) {
        // 一级标题：黑体，三号，加粗，左对齐，段前段后28磅
        para.Range.Font.Name = "黑体";
        para.Range.Font.Size = 16;
        para.Range.Font.Bold = -1;
        para.Alignment = 0; // 左对齐
        para.Format.FirstLineIndent = 0;
        para.Format.SpaceBefore = 28;
        para.Format.SpaceAfter = 28;
    } else if (i === 7 || i === 9) {
        // 二级标题：楷体_GB2312，三号，加粗，左对齐，首行缩进2字符
        para.Range.Font.Name = "楷体_GB2312";
        para.Range.Font.Size = 16;
        para.Range.Font.Bold = -1;
        para.Alignment = 0; // 左对齐
        para.Format.FirstLineIndent = Application.CentimetersToPoints(0.85);
        para.Format.SpaceBefore = 0;
        para.Format.SpaceAfter = 0;
    } else if (i === 17 || i === 18) {
        // 附件：仿宋_GB2312，三号，左对齐，无缩进
        para.Range.Font.Name = "仿宋_GB2312";
        para.Range.Font.Size = 16;
        para.Range.Font.Bold = 0;
        para.Alignment = 0; // 左对齐
        para.Format.FirstLineIndent = 0;
        para.Format.LineSpacingRule = 2;
        para.Format.LineSpacing = 28;
    } else if (i === 19) {
        // 落款：仿宋_GB2312，三号，左对齐
        para.Range.Font.Name = "仿宋_GB2312";
        para.Range.Font.Size = 16;
        para.Range.Font.Bold = 0;
        para.Alignment = 0; // 左对齐
        para.Format.FirstLineIndent = 0;
        para.Format.LineSpacingRule = 2;
        para.Format.LineSpacing = 28;
    } else if (i === 20) {
        // 日期：仿宋_GB2312，三号，左对齐
        para.Range.Font.Name = "仿宋_GB2312";
        para.Range.Font.Size = 16;
        para.Range.Font.Bold = 0;
        para.Alignment = 0; // 左对齐
        para.Format.FirstLineIndent = 0;
        para.Format.LineSpacingRule = 2;
        para.Format.LineSpacing = 28;
    } else {
        // 正文：仿宋_GB2312，三号，28磅行距，首行缩进2字符
        para.Range.Font.Name = "仿宋_GB2312";
        para.Range.Font.Size = 16;
        para.Range.Font.Bold = 0;
        para.Alignment = 0; // 左对齐
        para.Format.FirstLineIndent = Application.CentimetersToPoints(0.85);
        para.Format.LineSpacingRule = 2;
        para.Format.LineSpacing = 28;
    }
}

// 3. 设置页码（公文页码格式：4号半角宋体阿拉伯数字）
try {
    doc.Sections.Item(1).Footers.Item(1).PageNumbers.Add(2, false); // 2表示阿拉伯数字
    var pageNum = doc.Sections.Item(1).Footers.Item(1).PageNumbers.Item(1);
    pageNum.Alignment = 2; // 右对齐（单页码）
    pageNum.Font.Name = "宋体";
    pageNum.Font.Size = 14; // 四号字
} catch (e) {
    // 如果页码设置失败，继续执行
}

return "公文排版完成：已设置页面边距、字体、字号、行距、标题样式和页码格式";
